// Solo call_analyzed del agente OUTBOUND. Todo lo demás (call_started/ended,
// eventos del agente inbound si compartieran webhook) se descarta en silencio.
const AGENT_OUT = 'agent_042b9fbc990838ae4117315440';
const body = $json.body ?? $json;
if (body.event !== 'call_analyzed') return [];
const call = body.call || {};
if (call.agent_id !== AGENT_OUT) return [];

const an = call.call_analysis || {};
const custom = an.custom_analysis_data || {};
const meta = call.metadata || {};

// Si no hubo conexión real, el resultado lo dicta el disconnect_reason, no el LLM.
const NO_PICKUP = ['dial_no_answer', 'dial_busy', 'dial_failed', 'voicemail_reached', 'machine_detected'];
let resultado = custom.resultado_llamada || 'sin_conversacion';
if (NO_PICKUP.includes(call.disconnect_reason)) resultado = 'no_contesta';

const dur = call.duration_ms != null ? Math.round(call.duration_ms / 1000)
  : (call.end_timestamp && call.start_timestamp ? Math.round((call.end_timestamp - call.start_timestamp) / 1000) : null);

return [{ json: {
  call_id: call.call_id,
  lead_id: meta.lead_id ?? null,
  attempt: meta.attempt ?? null,
  resultado,
  motivo_no_interes: custom.motivo_no_interes || 'no_aplica',
  nuevo_contacto_preferido: custom.nuevo_contacto_preferido || 'ninguno',
  disconnect_reason: call.disconnect_reason || '',
  duration_s: dur,
  call_summary: an.call_summary || '',
}}];

// Decide qué hacer en Kommo según el resultado. El RPC ya garantizó idempotencia
// (si este nodo corre, es la PRIMERA vez que se procesa este call_id).
//
// NOTA visita_agendada: NO movemos el lead original a Lead Caliente a propósito —
// la tool Reservar del flow ya dispara el circuito estándar de confirmación
// (lead en Lead Caliente + salesbot 87865); mover también este lead duplicaría
// la plantilla de confirmación con el CF "Día de visita" vacío.
const ev = $('Filtrar evento').first().json;
const ENUM = { visita_agendada: 1027074, no_interesado: 1027076, pide_mas_info: 1027078,
               derivado_humano: 1027080, sin_conversacion: 1027082, no_contesta: 1027084 };
const RAMON = 15113339;
const r = ev.resultado;
const leadId = Number(ev.lead_id);
if (!leadId) return []; // sin lead_id en metadata no podemos actualizar Kommo

const patch = { id: leadId, custom_fields_values: [
  { field_id: 1376610, values: [{ enum_id: ENUM[r] || ENUM.sin_conversacion }] },
]};

const MOTIVO = { ya_compro: 'ya compró', cambio_zona: 'cambió de zona', presupuesto: 'presupuesto',
                 momento_incorrecto: 'mal momento', otro: 'otro motivo' };
let nota = `Llamada IA de reactivación (intento ${ev.attempt ?? '?'}) — resultado: ${r.replace(/_/g, ' ')}.`;
let task = null;

if (r === 'no_interesado') {
  patch.status_id = 143; // Venta Perdido
  nota += ` Motivo: ${MOTIVO[ev.motivo_no_interes] || 'no indicado'}. Lead cerrado automáticamente.`;
} else if (r === 'visita_agendada') {
  nota += ' La visita se gestionó por el circuito estándar de reserva (confirmación WA enviada).';
} else if (r === 'derivado_humano') {
  nota += ' El cliente pidió hablar con una persona — se le prometió que le llamamos.';
  task = { text: `LLAMAR HOY: ${ev.call_summary ? ev.call_summary.slice(0, 200) : 'cliente pidió hablar con una persona en llamada IA de reactivación'}`,
           hours: 4 };
} else if (r === 'pide_mas_info') {
  nota += ' Sigue interesado pero no agendó.';
  if (ev.nuevo_contacto_preferido && ev.nuevo_contacto_preferido !== 'ninguno')
    nota += ` Prefiere contacto por: ${ev.nuevo_contacto_preferido.replace(/_/g, ' ')}.`;
  task = { text: `Seguimiento: lead pidió más info en llamada IA de reactivación. ${ev.call_summary ? ev.call_summary.slice(0, 200) : ''}`.trim(),
           hours: 24 };
}
if (ev.nuevo_contacto_preferido === 'no_contactar') {
  nota += ' ⚠ Pidió NO ser contactado: desmarcar consentimiento outbound.';
  patch.custom_fields_values.push({ field_id: 1376604, values: [{ value: false }] });
}
if (ev.call_summary && r !== 'no_contesta') nota += `\n\nResumen: ${ev.call_summary}`;
if (ev.duration_s != null) nota += `\nDuración: ${ev.duration_s}s.`;

return [{ json: {
  call_id: ev.call_id, lead_id: leadId,
  patch_body: [patch],
  nota_body: [{ note_type: 'common', params: { text: nota } }],
  task_body: task ? [{ task_type_id: 1, text: task.text,
    complete_till: Math.floor(Date.now() / 1000) + task.hours * 3600,
    entity_id: leadId, entity_type: 'leads', responsible_user_id: RAMON }] : null,
}}];

